#!/bin/bash\n\n# Copilot CLI Skills - Development Setup Script\n# This script sets up the development environment and guides through feature completion\n\nset -e\n\necho \"\"\necho \"╔════════════════════════════════════════════════════════╗\"\necho \"║  GitHub Copilot CLI Skills - Development Setup         ║\"\necho \"╚════════════════════════════════════════════════════════╝\"\necho \"\"\n\n# Check Node.js installation\necho \"🔍 Checking prerequisites...\"\nif ! command -v node &> /dev/null; then\n    echo \"❌ Node.js is not installed. Please install Node.js 16 or higher.\"\n    exit 1\nfi\n\necho \"✅ Node.js version: $(node --version)\"\necho \"✅ npm version: $(npm --version)\"\n\n# Install dependencies\necho \"\"\necho \"📦 Installing dependencies...\"\nnpm install\n\necho \"\"\necho \"✅ Environment setup complete!\"\necho \"\"\necho \"🚀 Available commands:\"\necho \"\"\necho \"   npm start          - Start interactive menu\"\necho \"   npm run calculator - Run calculator\"\necho \"   npm run cli        - Run CLI tool\"\necho \"   npm run agent      - Run agent\"\necho \"   npm test           - Run tests\"\necho \"\"\necho \"📖 Documentation:\"\necho \"\"\necho \"   - README.md              - Main documentation\"\necho \"   - GETTING_STARTED.md     - Quick start guide\"\necho \"   - FEATURES.md            - Feature roadmap\"\necho \"   - IMPLEMENTATION.md      - Implementation details\"\necho \"\"\necho \"🎯 Next Steps:\"\necho \"\"\necho \"   1. Read GETTING_STARTED.md\"\necho \"   2. Choose a feature (CALCULATOR, CLI, or AGEN)\"\necho \"   3. Run 'npm run <feature>'\"\necho \"   4. Test and verify the application works\"\necho \"\"\n